import { initAos, initAosScale, initStaggeredAos } from './plugins/aos';
import { initLenis } from './plugins/lenis';
import { getLenis } from './plugins/lenis';
import { initTrMarquee } from './plugins/scroll-marquee';
import { createSplitText, initFadeEatchWordOnScroll, splitLines } from './plugins/split-text';

CustomEase.create('primary-ease', '0.62, 0.05, 0.01, 0.99');
CustomEase.create('primary-ease-out', '0.17,0.84,0.44,1');
CustomEase.create('smooth', '.15, .9, .34, .95');
CustomEase.create('custom', '.76, 0, .24, 1');

ScrollTrigger.defaults({
  markers: false,
  scroller: document.documentElement,
});

const sections = gsap.utils.toArray('.section');

/* semua elemen diambil per section supaya index selalu sama */

const images = sections.map((section) => section.querySelector('.project-image'));

const outerWrappers = sections.map((section) => section.querySelector('.outer'));

const innerWrappers = sections.map((section) => section.querySelector('.inner'));

/* headings per section */

const headings = sections.map((section) => section.querySelectorAll('.h2'));

/* SplitText */

const splitHeadings = headings.map((group) =>
  Array.from(group).map(
    (heading) =>
      new SplitText(heading, {
        type: 'chars,words,lines',
        charsClass: 'clip-text',
        mask: 'chars',
        maskClass: 'split-char-mask',
      })
  )
);

/* =============================
STATE
============================= */

let currentIndex = -1;
let animating = false;

const wrap = gsap.utils.wrap(0, sections.length);

/* =============================
INITIAL STATE
============================= */

gsap.set(sections, { autoAlpha: 0 });
gsap.set(outerWrappers, { yPercent: 100 });
gsap.set(innerWrappers, { yPercent: -100 });

/* =============================
SECTION TRANSITION
============================= */

function gotoSection(index, direction) {
  index = wrap(index);

  if (animating) return;

  animating = true;

  const fromTop = direction === -1;
  const dFactor = fromTop ? -1 : 1;

  const tl = gsap.timeline({
    defaults: { duration: 1.25, ease: 'power1.inOut' },
    onComplete: () => {
      animating = false;
    },
  });

  /* EXIT CURRENT */

  if (currentIndex >= 0) {
    gsap.set(sections[currentIndex], { zIndex: 0 });

    tl.to(
      images[currentIndex],
      {
        yPercent: -15 * dFactor,
      },
      0
    )

      .set(sections[currentIndex], {
        autoAlpha: 0,
      });
  }

  /* ENTER NEXT */

  gsap.set(sections[index], {
    autoAlpha: 1,
    zIndex: 1,
  });

  tl.fromTo(
    [outerWrappers[index], innerWrappers[index]],
    {
      yPercent: (i) => (i ? -100 * dFactor : 100 * dFactor),
    },
    {
      yPercent: 0,
    },
    0
  )

    .fromTo(images[index], { yPercent: 15 * dFactor }, { yPercent: 0 }, 0);

  /* TEXT ANIMATION */

  splitHeadings[index].forEach((split, i) => {
    tl.fromTo(
      split.chars,
      {
        autoAlpha: 1,
        xPercent: -150 * dFactor,
      },
      {
        autoAlpha: 1,
        xPercent: 0,
        duration: 1.25,
        ease: 'power1.inOut',
        stagger: {
          amount: 0.3,
          from: 'start',
        },
      },
      0.2 + i * 0.1
    );
  });

  currentIndex = index;
}

/* =============================
OBSERVER
============================= */

Observer.create({
  type: 'wheel,touch,pointer',

  wheelSpeed: -1,

  tolerance: 10,

  preventDefault: true,

  allowClicks: true,

  onDown: () => {
    if (!animating) gotoSection(currentIndex - 1, -1);
  },

  onUp: () => {
    if (!animating) gotoSection(currentIndex + 1, 1);
  },
});

/* =============================
INIT
============================= */

gotoSection(0, 1);

function initNav() {
  const navComponent = document.querySelector('.nav-component');
  if (!navComponent) return;

  let open = false;

  const backDrop = navComponent.querySelector('.nav-backdrop');

  const navbar = navComponent.querySelector('.navbar');

  const trigger = navbar.querySelector('.nav-trigger');
  const hamburger = trigger.querySelector('.hamburger-icon');
  const navMenuText = trigger.querySelectorAll('.text-16');

  const wrapper = navbar.querySelector('.nav-wrapper');
  const navLinks = wrapper.querySelectorAll('.nav-link');

  const tl = gsap.timeline({ paused: true, defaults: { ease: 'primary-ease' } });

  gsap.set(backDrop, { autoAlpha: 0 });
  gsap.set(navbar, { y: '-3.5em', yPercent: 100, clipPath: 'inset(0 35%)' });
  gsap.set(navLinks, { y: '10vh', autoAlpha: 0 });
  gsap.set(navMenuText, { y: '0%' });

  tl.to(backDrop, { autoAlpha: 1, duration: 0.4 })
    .to(
      navbar,
      {
        y: '-100%',
        clipPath: 'inset(0 0%)',
        duration: 0.6,
      },
      0
    )
    .to(
      navLinks,
      {
        y: '0%',
        autoAlpha: 1,
        stagger: { amount: 0.3, from: 'start' },
        duration: 0.6,
        ease: 'primary-ease-out',
      },
      0
    )
    .to(
      navMenuText,
      {
        y: '0%',
        autoAlpha: 1,
        duration: 0.4,
      },
      0
    );

  trigger.addEventListener('click', () => {
    if (tl.isActive()) return;

    open = !open;

    if (open) {
      tl.play();
    } else {
      tl.reverse();
    }
  });
}

function initApp() {
  const mm = gsap.matchMedia();

  initNav();
}

async function safeInit() {
  await document.fonts.ready;

  window.addEventListener('load', () => {
    initApp();

    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        ScrollTrigger.refresh(true);
      });
    });
  });
}

safeInit();

window.addEventListener('load', () => {
  window.scrollTo(0, 0);
});

window.addEventListener('resize', () => {
  ScrollTrigger.refresh();
});
